const today = new Date();
today.setHours(0,0,0,0);
const cutoff = new Date(today);
cutoff.setDate(today.getDate() + 14);

const qualifying = [];
for (const item of $input.all()) {
  const status = (item.json['Status'] || '').trim();
  const filmDateStr = (item.json['Film Date'] || '').trim();
  const filmDate = new Date(filmDateStr);
  filmDate.setHours(0,0,0,0);

  console.log('Episode: ' + item.json['Episode Title'] + ' | Status: ' + status + ' | Film Date: ' + filmDateStr + ' | Parsed: ' + filmDate + ' | inRange: ' + (filmDate >= today && filmDate <= cutoff));

  if (status !== 'Idea' && status !== 'Brief Ready') continue;
  if (!filmDateStr) continue;
  if (isNaN(filmDate.getTime())) continue;
  if (filmDate >= today && filmDate <= cutoff) {
    qualifying.push({json: item.json});
  }
}
return qualifying;

const briefItems = $input.all();
const episodeItems = $('Filter Episodes').all();
const today = new Date().toLocaleDateString('en-US', {month:'long', day:'numeric', year:'numeric'});
const results = [];

for (let i = 0; i < briefItems.length; i++) {
  const episode = episodeItems[i] ? episodeItems[i].json : {};
  const briefText = briefItems[i].json.content[0].text;
  const docTitle = (episode['Episode Title'] || 'Untitled') + ' \u2014 Filming Brief';
  const separator = '\u2501'.repeat(48);

  const contentLines = [
    'EPISODE #' + (episode['Episode #'] || '') + ': ' + (episode['Episode Title'] || ''),
    'Series: ' + (episode['Series'] || '') + '  |  Pillar ' + (episode['Pillar'] || ''),
    'Towns Featured: ' + (episode['Towns Featured'] || ''),
    'Film Date: ' + (episode['Film Date'] || ''),
    'Brief Generated: ' + today,
    '',
    separator,
    '',
    briefText,
    '',
    separator,
    'East of Dallas \u2014 lorettasercy.com  |  eXp Realty  |  License #0633703'
  ];

  results.push({
    json: {
      episodeNumber: episode['Episode #'] || '',
      episodeTitle: episode['Episode Title'] || '',
      series: episode['Series'] || '',
      filmDate: episode['Film Date'] || '',
      towns: episode['Towns Featured'] || '',
      docTitle: docTitle,
      docContent: contentLines.join('\n')
    }
  });
}
return results;

const items = $('Restore Episode Data').all();
const episodes = items.map(function(item) {
  return {
    episodeTitle: item.json.episodeTitle,
    docUrl: item.json.docUrl
  };
});
const count = episodes.length;
if (count === 0) return [];
const today = new Date().toLocaleDateString('en-US', {weekday:'long', month:'long', day:'numeric', year:'numeric'});
const lines = ['Hi Loretta,', ''];
lines.push('Your filming briefs for the week of ' + today + ' are ready. ' + count + ' episode' + (count !== 1 ? 's' : '') + ' queued:');
lines.push('');
episodes.forEach(function(ep, i) {
  lines.push((i + 1) + '. ' + ep.episodeTitle);
  lines.push('   ' + ep.docUrl);
  lines.push('');
});
lines.push('Each brief includes 3 hook options, talking points in your voice, compliance flags, b-roll suggestions, and your verbal CTA.');
lines.push('');
lines.push('\u2014 East of Dallas AgentOS');
const result = {
  emailBody: lines.join('\n'),
  emailSubject: 'Your filming briefs are ready (' + count + ' episode' + (count !== 1 ? 's' : '') + ')',
  episodeCount: count
};
return [{ json: result }];

const result = {
  documentId: $json.documentId,
  docUrl: $json.docUrl,
  episodeTitle: $json.episodeTitle,
  episodeNumber: $json.episodeNumber,
  requestBody: JSON.stringify({
    requests: [{
      insertText: {
        location: { index: 1 },
        text: $json.docContent
      }
    }]
  })
};
return result;

